    "history_move_up_btn": "Mover this recursos up in the list order.",
    "history_rename_btn": "Rename this recursos for easier identification.",
    "history_save_unit_btn": "Guardar changes to this unit's name and organization.",
    "history_unit_name_input": "Introduzir a name for this unit (e.g., 'Week 3 - Ecosystems').",
